SELECT MAX(index), Time,DeviceId,Channel,Number,Distance,Wavelength FROM `wavedata`
where Channel in

    #{item}

and Time < #{time}
group by Channel
ORDER BY Time desc

SELECT `Index`,Time,DeviceId,Channel,Number,Distance,Wavelength FROM `wavedata`
where Channel =#{channelId}
and time < #{time}
ORDER BY Time desc
limit #{count}
